text:
{
  "formal_minutes": {
    "decisions": [
      {
        "type": "확정 결정",
        "item": "공개 릴리즈 목표는 '금요일 15:00 KST'로 유지하되, 스모크 테스트 통과를 전제로 한다."
      },
      {
        "type": "확정 결정",
        "item": "smoke-theme-pack.mjs에서 packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 재검토한다."
      },
      {
        "type": "확정 액션",
        "item": "Minjun이 금요일 10:00 KST까지 smoke test를 재실행하고 결과를 공유한다."
      },
      {
        "type": "확정 액션",
        "item": "Doyun이 금요일 12:00 KST까지 action_items.md에 failure triage note를 작성한다."
      },
      {
        "type": "확정 액션",
        "item": "Hara가 Minjun의 smoke 결과 게시 이후 생성된 tarball 경로를 확인한다."
      }
    ],
    "rejected_proposals": [
      {
        "type": "거부",
        "item": "Hara의 'packageName mismatch를 무시하도록 smoke-theme-pack.mjs 수정' 제안은 반려됨."
      }
    ],
    "internal_stretch_goals": [
      {
        "type": "내부 Stretch Goal",
        "item": "수요일 공개 릴리즈 제안은 내부 stretch goal로만 다뤄졌고, 최종 확정 목표는 아니다."
      },
      {
        "type": "내부 Stretch Goal",
        "item": "Seoyeon의 README 설치 단계 검토는 '목요일까지 가능하면' 수행 희망으로 언급되었으며, 소유자와 확정 기한은 없음."
      }
    ],
    "non_decisions": [
      {
        "type": "미결",
        "item": "README 설치 단계 리뷰는 제안만 있었을 뿐 담당자·확정 기한이 지정되지 않음."
      }
    ],
    "risks": [
      {
        "type": "위험",
        "item": "잘못된 tarball 경로 지정은 릴리즈 지연으로 이어질 수 있음."
      },
      {
        "type": "위험",
        "item": "README 설치 단계가 오래되면 릴리즈 노트가 사용자에게 오도 정보를 제공할 수 있음."
      }
    ],
    "open_questions": [
      {
        "type": "질문",
        "item": "최종 공개 릴리즈 승인 권한자는 누구인가?"
      },
      {
        "type": "질문",
        "item": "릴리즈 노트에 내부 Wednesday stretch goal을 언급할지 여부"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test 재실행 및 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 게시 후 생성 tarball 경로 확인",
      "due": "미정(결과 공유 후)",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토",
      "due": "목표 수준: 목요일(가능하면), 확정 기한 미정",
      "status": "미확정",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 기준 Minjun의 smoke test 결과 존재 여부 확인",
      "Doyun의 failure triage note(action_items.md) 작성 여부 확인",
      "Hara가 tarball 경로 검토를 완료했는지, 오차 여부 확인",
      "최종 릴리즈 승인 권한자 확인 및 기록",
      "릴리즈 노트에 Wednesday stretch goal을 넣을지 최종 결정"
    ],
    "what_not_to_invent": [
      "고객명, 예산, 보안 사고, 장애, 법무 승인 필요성, 소유자 미지정 항목의 임의 지정",
      "정해지지 않은 기한을 날짜/시간으로 임의 생성",
      "README 검토자, 승인권자, 법적·보안적 제약사항에 대한 추정"
    ]
  },
  "non_invention_rules": [
    "회의록에 명시되지 않은 사실(고객, 예산, 보안 이슈, 장애, 법무 승인)은 작성하지 않는다.",
    "미확정 항목은 확정처럼 기록하지 않고 '미지정/미정/미확정'으로 분리한다.",
    "제안과 결정의 경계를 분리한다(예: rejected proposal vs confirmed decision).",
    "내부 stretch goal과 공식 공개 목표를 혼동하지 않는다.",
    "모든 액션 아이템은 owner/task/due/status/source_certainty 형식을 유지하며, 근거 없는 확정값을 추가하지 않는다."
  ]
}
